solution: ```class ParkingSystem {
public:
    int slots[4]; // index 1,2,3 used for big, medium, small

    ParkingSystem(int big, int medium, int small) {
        slots[1] = big;
        slots[2] = medium;
        slots[3] = small;
    }

    bool addCar(int carType) {
        if (slots[carType] > 0) {
            --slots[carType];
            return true;
        }
        return false;
    }
};
```
